BEGIN
  BEGIN ORDS.DEFINE_TEMPLATE(p_module_name=>'arkia.api',p_pattern=>'app'); EXCEPTION WHEN OTHERS THEN NULL; END;
  BEGIN ORDS.DEFINE_HANDLER(p_module_name=>'arkia.api',p_pattern=>'app',p_method=>'GET',p_source_type=>ORDS.source_type_media,
    p_source=>q'~SELECT 'text/html; charset=utf-8' AS content_type, APEX_WEB_SERVICE.CLOBBASE642BLOB(b64) AS content FROM api_app WHERE id=1~'); EXCEPTION WHEN OTHERS THEN NULL; END;
  BEGIN ORDS.DEFINE_TEMPLATE(p_module_name=>'arkia.api',p_pattern=>'assets/:name'); EXCEPTION WHEN OTHERS THEN NULL; END;
  BEGIN ORDS.DEFINE_HANDLER(p_module_name=>'arkia.api',p_pattern=>'assets/:name',p_method=>'GET',p_source_type=>ORDS.source_type_media,
    p_source=>q'~SELECT mime AS content_type, APEX_WEB_SERVICE.CLOBBASE642BLOB(b64) AS content FROM api_assets WHERE name=:name~'); EXCEPTION WHEN OTHERS THEN NULL; END;
  COMMIT;
END;
/
